import{Environment,Functions,Server}from"Beckhoff.TwinCAT.HMI.Framework/index.esm.js";export function GoToLoginPage(){if(4!==Server.getCurrentUserConfig().state)return!1;const url=new URL(Environment.getServerSidePathAndQuery(),window.location.href);url.searchParams.delete("Location");const baseLocation=url.pathname+url.search+url.hash;return window.location.href=Environment.getHostBaseUri()+"/Login?Location="+baseLocation,!0}Functions.registerFunctionEx("GoToLoginPage","TcHmi.Functions.Beckhoff",GoToLoginPage,{injectInGlobalObject:!0});